import{_ as p,c as t,o as a,ae as i}from"./chunks/framework.BvcDoAct.js";const A=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2/PART0/前言.md","filePath":"zh-cn/Management2/PART0/前言.md"}'),l={name:"zh-cn/Management2/PART0/前言.md"};function n(_,e,r,o,s,c){return a(),t("div",null,[...e[0]||(e[0]=[i("<p>前言</p><p>被这个颇为宏大的副标题所吸引而翻开本书的读者，读到下面这句话可能会有些“落空”的感觉：事实上，如今在世界与日本的音乐行业之间，并不存在所谓的“壁垒”。只要能够先传达清楚这一前提，这篇前言的使命其实就已经完成了，但还是请允许我再稍作展开。请允许我先从自我介绍开始。</p><p>初次见面的朋友，初次见面；一直以来给予关注的各位，也由衷感谢。我是株式会社BMSG的代表取缔役CEO日高。同时，我也以“SKY-HI”这一名义，自十几岁起作为一名Rapper持续积累自己的职业生涯，并自2021年起，担任包括BE:FIRST在内的男子组合制作人等工作。三个身份同时推进的每一天，与其说是充满刺激，不如说更像是不安与幸福交织缠绕、如绳索般紧密相连的日子。某种意义上，也算是一段颇为奇特的人生。</p><p>此外，我也曾以“日高光启”之名，在AAA这一组合中活动了约二十年（目前处于暂停活动状态）。再往前追溯，自中学时期起我便已投身演艺行业。在这段时间里，我先后经历了：</p><ul><li>国内最大型事务所的偶像练习生</li><li>乐队成员</li><li>另一家大型事务所的练习生</li><li>AAA成员</li><li>地下说唱歌手</li><li>独立音乐厂牌负责人</li><li>创立BMSG</li><li>从事制作人工作</li></ul><p>就这样在音乐行业与演艺圈之间不断辗转。尤其作为Rapper与作曲人，无论是在独立还是主流体系中，日本大多数音乐相关公司我大多都有过合作；也曾与海外艺人共同创作、进行世界巡演……写到这里不禁觉得，自己还真是毫不厌倦地做了各种各样的事情。</p><p>按理来说，艺人专注于某一件事，默默打磨自身风格，或许才更显得“纯粹而帅气”。但不知是幸运还是不幸，这种近乎“多动症”的经历，反而让我对音乐行业的理解变得更加立体、清晰。</p><p>而最让我感到惊讶的是，在我经历了如此多不同阶段与角色的这段时间——也就是直到自己创业为止的大约二十年间，日本音乐产业的根本结构，以及演艺圈的运作生态，几乎没有发生任何改变。</p><p>日本与世界音乐之间存在的，并不是什么“壁垒”，而只是单纯的“时差”。而互联网这一发明，本质上正是消弭这种时差（无论利弊）的工具。因此，日本音乐被世界听见的路径，其实早已存在。甚至可以说，现实中已经有大量听众，正是沿着这条路径在聆听日本音乐。</p><p>那么，为什么这条路径至今仍未被更多人真正走通？为什么BMSG会相信自己能够打破这种“时差”，并满怀信心地为此做准备？如果本书能够将这些问题逐步呈现出来，并进一步促使你心中的某些“常识”发生改变，而这种改变又不断连接、扩散开来——那么，这一切终将把我们带向更广阔的世界。</p><p>那么，就请先准备好你的护照吧。</p>",11)])])}const d=p(l,[["render",n]]);export{A as __pageData,d as default};
